import {
  resolveWorkflowSourceFilePathForContext,
  workflowSourceFolderHint,
  workflowSourceScopeError,
  WORKFLOW_COMPILER_ALLOWED_FILES,
} from '@main/workflows/workflow-source-scope'
import {
  attachValidationMessage,
  validateEntitiesDefinitionJsonSource,
  validateWorkflowDefinitionJsonSource,
} from '@main/workflows/workflow-source-validate'
import {
  ENTITIES_DEFINITION_JSON_FILENAME,
  WORKFLOW_DEFINITION_JSON_FILENAME,
  parseWorkflowDefinitionBodyJson,
  safeParseEntitiesDefinitionJson,
  serializeEntitiesDefinition,
  serializeWorkflowDefinitionBody,
} from '@shared/workflows/source-files'
import {
  parseWorkflowEntities,
  parseWorkflowEntityField,
} from '@shared/workflows/definition-serialization'
import { replace } from '@toolSet/file-system/edit-replace'
import {
  convertToLineEnding,
  detectLineEnding,
  normalizeLineEndings,
} from '@toolSet/file-system/file-io-utils'

type CompilerContext = {
  workflowId: string
  workflowName: string
  knownTools?: Set<string>
  sourceDir?: string
}

type Validation = {
  valid: boolean
  errors: string[]
  warnings: string[]
}

type EntitiesArrayResult = {
  path: string
  raw: string
  entities: ReturnType<typeof parseWorkflowEntities>
  parseErrors: string[]
}

function getContext(): CompilerContext {
  const ctx = requireWorkflowCompileContext()
  return {
    workflowId: ctx.workflowId,
    workflowName: ctx.workflowName,
    knownTools: ctx.knownTools,
    sourceDir: ctx.sourceDir,
  }
}

async function readTextFileIfExists(filePath: string): Promise<string | null> {
  try {
    return await fs.readFile(filePath, 'utf-8')
  } catch {
    return null
  }
}

function workflowDir(ctx: CompilerContext): string {
  return workflowSourceFolderHint(ctx.workflowId, ctx.sourceDir)
}

async function ensureParent(filePath: string): Promise<void> {
  await fs.mkdir(dirname(filePath), { recursive: true })
}

function canonicalizeWorkflowBody(content: string): string {
  const parsed = parseWorkflowDefinitionBodyJson(content)
  return serializeWorkflowDefinitionBody(parsed)
}

async function persistWorkflowBodyContent(
  ctx: CompilerContext,
  path: string,
  content: string,
): Promise<Validation> {
  await ensureParent(path)
  await fs.writeFile(path, content, 'utf-8')
  return validateWorkflowDefinitionJsonSource(ctx, content)
}

async function readEntitiesArray(ctx: CompilerContext): Promise<EntitiesArrayResult> {
  const path = resolveWorkflowSourceFilePathForContext(
    ctx,
    ENTITIES_DEFINITION_JSON_FILENAME,
  )
  const raw = (await readTextFileIfExists(path)) ?? '[]\n'
  const parsed = safeParseEntitiesDefinitionJson(raw)
  if (!parsed.success) {
    return { path, raw, entities: [], parseErrors: parsed.errors }
  }
  return {
    path,
    raw,
    entities: parsed.data,
    parseErrors: [],
  }
}

async function persistEntitiesArray(
  ctx: CompilerContext,
  path: string,
  entities: ReturnType<typeof parseWorkflowEntities>,
): Promise<{ content: string; validation: Validation; entities: ReturnType<typeof parseWorkflowEntities> }> {
  const content = serializeEntitiesDefinition(entities)
  await ensureParent(path)
  await fs.writeFile(path, content, 'utf-8')
  const validation = validateEntitiesDefinitionJsonSource(ctx, content)
  return { content, validation, entities: parseWorkflowEntities(JSON.parse(content)) }
}

async function listWorkflowFiles(): Promise<Record<string, unknown>> {
  const ctx = getContext()
  const files = await Promise.all(
    WORKFLOW_COMPILER_ALLOWED_FILES.map(async (file) => {
      const path = resolveWorkflowSourceFilePathForContext(ctx, file)
      const exists = await fs
        .stat(path)
        .then((s) => s.isFile())
        .catch(() => false)
      return { path: file, exists }
    }),
  )
  return {
    workflowSourceDir: workflowDir(ctx),
    allowedFiles: [...WORKFLOW_COMPILER_ALLOWED_FILES],
    files,
  }
}

async function readWorkflowDefinitionFile(): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    const path = resolveWorkflowSourceFilePathForContext(
      ctx,
      WORKFLOW_DEFINITION_JSON_FILENAME,
    )
    const content = await fs.readFile(path, 'utf-8')
    return {
      file: WORKFLOW_DEFINITION_JSON_FILENAME,
      workflowSourceDir: workflowDir(ctx),
      content,
    }
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

async function writeWorkflowDefinitionFile(
  content: string,
): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    const path = resolveWorkflowSourceFilePathForContext(
      ctx,
      WORKFLOW_DEFINITION_JSON_FILENAME,
    )
    const validation = await persistWorkflowBodyContent(ctx, path, content)
    const canonicalContent = validation.valid ? canonicalizeWorkflowBody(content) : content
    return attachValidationMessage(
      {
        written: true,
        file: WORKFLOW_DEFINITION_JSON_FILENAME,
        workflowSourceDir: workflowDir(ctx),
        content: canonicalContent,
      },
      validation,
    )
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

async function editJsonFile(args: {
  ctx: CompilerContext
  fileName: typeof WORKFLOW_DEFINITION_JSON_FILENAME | typeof ENTITIES_DEFINITION_JSON_FILENAME
  oldString: string
  newString: string
  replaceAll: boolean
  persist: (ctx: CompilerContext, path: string, content: string) => Promise<Validation>
}): Promise<Record<string, unknown>> {
  const path = resolveWorkflowSourceFilePathForContext(args.ctx, args.fileName)
  const contentOld = await fs.readFile(path, 'utf-8')
  const ending = detectLineEnding(contentOld)
  const oldNormalized = convertToLineEnding(
    normalizeLineEndings(args.oldString),
    ending,
  )
  const newNormalized = convertToLineEnding(
    normalizeLineEndings(args.newString),
    ending,
  )

  let contentNew: string
  try {
    contentNew = replace(contentOld, oldNormalized, newNormalized, args.replaceAll)
  } catch (err) {
    return { error: err instanceof Error ? err.message : 'Failed to edit JSON file' }
  }

  const validation = await args.persist(args.ctx, path, contentNew)
  return attachValidationMessage(
    {
      written: true,
      file: args.fileName,
      workflowSourceDir: workflowDir(args.ctx),
      action: 'modify',
    },
    validation,
  )
}

async function editWorkflowDefinitionFile(
  oldString: string,
  newString: string,
  replaceAll: boolean,
): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    return editJsonFile({
      ctx,
      fileName: WORKFLOW_DEFINITION_JSON_FILENAME,
      oldString,
      newString,
      replaceAll,
      persist: persistWorkflowBodyContent,
    })
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

async function readEntitiesDefinitionFile(): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    const { raw, entities, parseErrors } = await readEntitiesArray(ctx)
    if (parseErrors.length > 0) {
      return {
        file: ENTITIES_DEFINITION_JSON_FILENAME,
        workflowSourceDir: workflowDir(ctx),
        content: raw,
        valid: false,
        validationErrors: parseErrors,
      }
    }
    return {
      file: ENTITIES_DEFINITION_JSON_FILENAME,
      workflowSourceDir: workflowDir(ctx),
      content: raw.trim() ? serializeEntitiesDefinition(entities) : '[]\n',
      entities,
      valid: true,
    }
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

async function writeEntitiesDefinitionFile(
  content: string,
): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    const { path } = await readEntitiesArray(ctx)
    const parsed = safeParseEntitiesDefinitionJson(content)
    if (!parsed.success) {
      return attachValidationMessage(
        {
          written: false,
          file: ENTITIES_DEFINITION_JSON_FILENAME,
          workflowSourceDir: workflowDir(ctx),
        },
        { valid: false, errors: parsed.errors, warnings: [] },
      )
    }

    const saved = await persistEntitiesArray(ctx, path, parsed.data)
    return attachValidationMessage(
      {
        written: true,
        file: ENTITIES_DEFINITION_JSON_FILENAME,
        workflowSourceDir: workflowDir(ctx),
        entities: saved.entities,
        content: saved.content,
      },
      saved.validation,
    )
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

async function editEntitiesDefinitionFile(
  oldString: string,
  newString: string,
  replaceAll: boolean,
): Promise<Record<string, unknown>> {
  const ctx = getContext()
  try {
    const result = await editJsonFile({
      ctx,
      fileName: ENTITIES_DEFINITION_JSON_FILENAME,
      oldString,
      newString,
      replaceAll,
      persist: async (innerCtx, path, updatedContent) => {
        const parsed = safeParseEntitiesDefinitionJson(updatedContent)
        if (!parsed.success) {
          await ensureParent(path)
          await fs.writeFile(path, updatedContent, 'utf-8')
          return { valid: false, errors: parsed.errors, warnings: [] }
        }
        const saved = await persistEntitiesArray(innerCtx, path, parsed.data)
        return saved.validation
      },
    })

    if ('error' in result && result.error) {
      return result
    }

    const { raw, entities, parseErrors } = await readEntitiesArray(ctx)
    const content = parseErrors.length === 0 ? serializeEntitiesDefinition(entities) : raw
    return {
      ...result,
      entities,
      content,
    }
  } catch (err) {
    return workflowSourceScopeError(err)
  }
}

function findEntity(
  entities: ReturnType<typeof parseWorkflowEntities>,
  entityId: string,
) {
  return entities.find((entity) => entity.id === entityId)
}

async function addEntityField(input: {
  entity_id: string
  field: unknown
  entity_name?: string
  entity_description?: string
}): Promise<Record<string, unknown>> {
  const entityId = String(input.entity_id ?? '').trim()
  if (!entityId) return { error: 'entity_id is required' }

  let field
  try {
    field = parseWorkflowEntityField(input.field)
  } catch (err) {
    return {
      error: err instanceof Error ? err.message : 'Invalid field object',
    }
  }

  const ctx = getContext()
  const { path, entities } = await readEntitiesArray(ctx)
  let entity = findEntity(entities, entityId)
  if (!entity) {
    entity = {
      id: entityId,
      name: String(input.entity_name ?? entityId).trim() || entityId,
      description: input.entity_description?.trim() || undefined,
      fields: [],
    }
    entities.push(entity)
  }

  if (entity.fields.some((f) => f.key === field.key)) {
    return { error: `Field "${field.key}" already exists on entity "${entityId}"` }
  }

  entity.fields.push(field)
  const saved = await persistEntitiesArray(ctx, path, entities)
  return attachValidationMessage(
    {
      written: true,
      action: 'add_entity_field',
      file: ENTITIES_DEFINITION_JSON_FILENAME,
      workflowSourceDir: workflowDir(ctx),
      entity_id: entityId,
      field_key: field.key,
      entities: saved.entities,
      content: saved.content,
    },
    saved.validation,
  )
}

async function updateEntityField(input: {
  entity_id: string
  field_key: string
  field: unknown
}): Promise<Record<string, unknown>> {
  const entityId = String(input.entity_id ?? '').trim()
  const fieldKey = String(input.field_key ?? '').trim()
  if (!entityId || !fieldKey) {
    return { error: 'entity_id and field_key are required' }
  }

  let field
  try {
    field = parseWorkflowEntityField(input.field)
  } catch (err) {
    return {
      error: err instanceof Error ? err.message : 'Invalid field object',
    }
  }

  const ctx = getContext()
  const { path, entities } = await readEntitiesArray(ctx)
  const entity = findEntity(entities, entityId)
  if (!entity) return { error: `Entity not found: ${entityId}` }

  const index = entity.fields.findIndex((f) => f.key === fieldKey)
  if (index < 0) {
    return { error: `Field not found: ${fieldKey} on entity ${entityId}` }
  }

  entity.fields[index] = { ...field, key: fieldKey }
  const saved = await persistEntitiesArray(ctx, path, entities)
  return attachValidationMessage(
    {
      written: true,
      action: 'update_entity_field',
      file: ENTITIES_DEFINITION_JSON_FILENAME,
      workflowSourceDir: workflowDir(ctx),
      entity_id: entityId,
      field_key: fieldKey,
      entities: saved.entities,
      content: saved.content,
    },
    saved.validation,
  )
}

async function deleteEntityField(input: {
  entity_id: string
  field_key: string
}): Promise<Record<string, unknown>> {
  const entityId = String(input.entity_id ?? '').trim()
  const fieldKey = String(input.field_key ?? '').trim()
  if (!entityId || !fieldKey) {
    return { error: 'entity_id and field_key are required' }
  }

  const ctx = getContext()
  const { path, entities } = await readEntitiesArray(ctx)
  const entity = findEntity(entities, entityId)
  if (!entity) return { error: `Entity not found: ${entityId}` }

  const nextFields = entity.fields.filter((f) => f.key !== fieldKey)
  if (nextFields.length === entity.fields.length) {
    return { error: `Field not found: ${fieldKey} on entity ${entityId}` }
  }

  if (nextFields.length === 0) {
    const withoutEntity = entities.filter((e) => e.id !== entityId)
    const saved = await persistEntitiesArray(ctx, path, withoutEntity)
    return attachValidationMessage(
      {
        written: true,
        action: 'delete_entity_field',
        file: ENTITIES_DEFINITION_JSON_FILENAME,
        workflowSourceDir: workflowDir(ctx),
        entity_id: entityId,
        field_key: fieldKey,
        removed_entity: true,
        entities: saved.entities,
        content: saved.content,
      },
      saved.validation,
    )
  }

  entity.fields = nextFields
  const saved = await persistEntitiesArray(ctx, path, entities)
  return attachValidationMessage(
    {
      written: true,
      action: 'delete_entity_field',
      file: ENTITIES_DEFINITION_JSON_FILENAME,
      workflowSourceDir: workflowDir(ctx),
      entity_id: entityId,
      field_key: fieldKey,
      entities: saved.entities,
      content: saved.content,
    },
    saved.validation,
  )
}

